mapper.sql:
SELECT T.ID, T.USER_ID, T.GOODS_ID, T.ADD_TIME, T.REFERRER, U.NICKNAME FROM MALL_FOOTPRINT T LEFT JOIN WX_USER U ON T.USER_ID = U.ID WHERE 1=1
AND T.ID = #{params.id}
AND T.USER_ID = #{params.userId}
AND T.NAME LIKE '%${params.name}%'

mapper.select:
select f.id,f.user_id,f.goods_id,f.add_time add_time,f.referrer,
g.name as name, g.list_pic_url, g.goods_brief as goods_brief,
g.retail_price as retail_price,
u.nickname as nickname,u.avatar as avatar
from mall_footprint f
left join mall_goods g on f.goods_id = g.id
left join mall_user u on u.id = f.user_id

    u.id is not null

        and f.user_id = #{userId}


        and f.referrer = #{referrer}




        order by ${sidx} ${order}


        order by f.id desc



    limit #{offset}, #{limit}

select f.id,f.user_id,f.goods_id,f.add_time add_time,f.referrer, g.name as name, g.list_pic_url, g.goods_brief as goods_brief, g.retail_price as retail_price from mall_footprint f
left join mall_footprint max on f.goods_id = max.goods_id and f.user_id = max.user_id and max.add_time > f.add_time
left join mall_goods g on f.goods_id = g.id
and f.user_id = #{userId}
and max.id is null
order by ${sidx} ${order}
order by f.id desc
limit #{offset}, #{limit}
